ApiZona
{
	[Description("Recupera la Lista de Conceptos de Caja cargados.")]
	[RestMethod(GET)]
	Listar(in:&Buscar_ZonaNombre, out:&ZonaListaSDT)
 => ZonaLista_DP(in:&Buscar_ZonaNombre,out:&ZonaListaSDT);

 	[Description("Recupera un Conceptos de Caja")]
 	[RestMethod(GET)]
 	Buscar(in:&Buscar_ZonaId, out:&ZonaSDT)
 => Zona_DP(in:&Buscar_ZonaId,out:&ZonaSDT);

 	[Description("Graba un Nuevo de Conceptos de Caja")]
 	[RestMethod(POST)]
 	Insertar(in:&Buscar_ZonaNombre, out:&Messages)
 => Zona_Insertar(in:&Buscar_ZonaNombre,out:&Messages);

 	[Description("Modificar un Conceptos de Caja existente")]
 	[RestMethod(PUT)]
 	Modificar(in:&Buscar_ZonaId,in:&Buscar_ZonaNombre, out:&Messages)
 => Zona_Modificar(in:&Buscar_ZonaId,in:&Buscar_ZonaNombre,out:&Messages);

 	[Description("Borrar un Conceptos de Caja existente")]
 	[RestMethod(DELETE)]
 	Borrar(in:&Buscar_ZonaId,out:&Messages)
 => Zona_Borrar(in:&Buscar_ZonaId,out:&Messages);
	}

/////////////////////////////
// Insertar Concepto de Caja 

&Zona.ZonaNombre = &ZonaNombre
If &Zona.Insert()
	Commit
Else
	Rollback
Endif
// Devuelve mensajes
&Messages = &Zona.GetMessages()

parm(in:&ZonaCodigo,
	in:&ZonaNombre,
	out:&Messages);

Zona_SDT From Zona
where ZonaId = &ZonaId 
{
	ZonaId  /*Concepto Caja Id value*/
	ZonaNombre  /*Concepto Caja Nombre value*/
	ExisteSioNo = SioNo.Si /*Existe Sio No value*/
}
Zona_SDT [Default]
{
	ExisteSioNo = SioNo.No /*Existe Sio No value*/
}

ZonaListaSDT From Zona
Order ZonaNombre
Where ZonaNombre like  &ZonaNombre when Not &ZonaNombre.IsEmpty()
{
	ZonaListaSDTItem
	{
		ZonaId  /*Concepto Caja Id value*/
		ZonaNombre  /*Concepto Caja Nombre value*/
	}
}
